To query a DynamoDB table for items where a list attribute contains a specific string, use the `contains` comparison operator in a `FilterExpression`. For example, to find items where the `info.genres` list contains the string "Biography", structure your query as follows:

javascript
var params = {
  TableName: TABLE_NAME,
  KeyConditionExpression: "year = :yyyy",
  FilterExpression: `contains(info.genres, :qqqq)`,
  ExpressionAttributeValues: {
    ":yyyy": 2013,
    ":qqqq": "Biography"
  }
};

var AWS = require("aws-sdk");
var docClient = new AWS.DynamoDB.DocumentClient();
let promise = docClient.query(params).promise();
promise.then(res => {
  console.log("res:", res);
});


This will return all items from the year 2013 where the `genres` list includes "Biography".

To query items by a partition key (e.g., `year`) and filter by a list attribute, combine `KeyConditionExpression` for the partition key and `FilterExpression` for the list. For example:

javascript
var params = {
  TableName: TABLE_NAME,
  KeyConditionExpression: "year = :yyyy",
  FilterExpression: "contains(info.genres, :genre)",
  ExpressionAttributeValues: {
    ":yyyy": 2013,
    ":genre": "Biography"
  }
};

var AWS = require("aws-sdk");
var docClient = new AWS.DynamoDB.DocumentClient();
docClient.query(params, function(err, data) {
  if (err) console.log(err);
  else console.log(data.Items);
});


This query will return items from 2013 where the `genres` list includes "Biography".

Yes, the `contains` operator works with DynamoDB DocumentClient for querying nested list attributes. For example, to check if a list within a nested object (like `info.genres`) contains a value, use:

javascript
var params = {
  TableName: TABLE_NAME,
  KeyConditionExpression: "year = :yyyy",
  FilterExpression: "contains(info.genres, :genre)",
  ExpressionAttributeValues: {
    ":yyyy": 2013,
    ":genre": "Drama"
  }
};

var docClient = new AWS.DOCDynamoDB.DocumentClient();
docClient.query(params).promise().then(data => {
  console.log("Matching items:", data.Items);
});


This will return items from 2013 where the `genres` list includes "Drama".

For DynamoDB queries targeting a list of strings, you can use the `contains` operator in the `FilterExpression` to check for the presence of a specific string. For example:

javascript
var params = {
  TableName: TABLE_NAME,
  KeyConditionExpression: "year = :yyyy",
  FilterExpression: "contains(info.genres, :genre)",
  ExpressionAttributeValues: {
    ":yyyy": 2013,
    ":genre": "Thriller"
  }
};

var docClient = new AWS.DynamoDB.DocumentClient();
docClient.query(params).promise().then(res => {
  console.log("Items with 'Thriller':", res.Items);
});


This query will return all items from 2013 where the `genres` list includes "Thriller". For exact matches of the entire list, use `=` with the full list as the value.

When querying nested attributes in DynamoDB, you can use `ExpressionAttributeNames` to simplify attribute names or avoid conflicts with reserved words. For example:

javascript
var params = {
  TableName: TABLE_NAME,
  KeyConditionExpression: "#yr = :yyyy",
  FilterExpression: "contains(#info.#genres, :genre)",
  ExpressionAttributeNames: {
    "#yr": "year",
    "#info": "info",
    "#genres": "genres"
  },
  ExpressionAttributeValues: {
    ":yyyy": 2013,
    ":genre": "Action"
  }
};

var docClient = new AWS.DynamoDB.DocumentClient();
docClient.query(params).promise().then(res => {
  console.log("Items with 'Action':", res.Items);
});


This approach is useful when attribute names might conflict with DynamoDB reserved words or when simplifying complex nested attribute paths.
